265→// Logout button — wire up click handler once.
266→const logoutBtn = document.getElementById("logoutBtn");
267→const settingsBtn = document.getElementById("settingsBtn");
268→const mobileMenuBtn = document.getElementById("mobileMenuBtn");
269→const mobileMenuOverlay = document.getElementById("mobileMenuOverlay");
270→const mobileMenuPanel = document.getElementById("mobileMenuPanel");
271→const mobileMenuSessionsBtn = document.getElementById("mobileMenuSessionsBtn");
272→const mobileMenuSettingsBtn = document.getElementById("mobileMenuSettingsBtn");
273→const mobileMenuLogoutBtn = document.getElementById("mobileMenuLogoutBtn");
274→
275→function closeMobileMenu(): void {
276→	if (mobileMenuPanel) mobileMenuPanel.classList.remove("open");
277→	if (mobileMenuOverlay) mobileMenuOverlay.classList.remove("visible");
278→}
279→
280→function toggleMobileMenu(): void {
281→	if (!(mobileMenuPanel && mobileMenuOverlay)) return;
282→	const isOpen = mobileMenuPanel.classList.contains("open");
283→	if (isOpen) {
284→		closeMobileMenu();
285→		return;
286→	}
287→	mobileMenuPanel.classList.add("open");
288→	mobileMenuOverlay.classList.add("visible");
289→}
290→
291→function performLogout(): void {
292→	closeMobileMenu();
293→	fetch("/api/auth/logout", { method: "POST" }).finally(() => {
294→		location.href = "/";
295→	});
296→}
297→
298→if (logoutBtn) {
299→	logoutBtn.addEventListener("click", performLogout);
300→}
301→if (settingsBtn) {
302→	settingsBtn.addEventListener("click", () => {
303→		closeMobileMenu();
304→		navigate(routes.identity as string);
305→	});
306→}
307→if (mobileMenuBtn) {
308→	mobileMenuBtn.addEventListener("click", (e) => {
309→		e.stopPropagation();
310→		toggleMobileMenu();
311→	});
312→}
313→if (mobileMenuOverlay) {
314→	mobileMenuOverlay.addEventListener("click", closeMobileMenu);
315→}
316→if (mobileMenuSettingsBtn) {
317→	mobileMenuSettingsBtn.addEventListener("click", () => {
318→		closeMobileMenu();
319→		navigate(routes.identity as string);
320→	});
321→}
322→if (mobileMenuSessionsBtn) {
323→	mobileMenuSessionsBtn.addEventListener("click", () => {
324→		closeMobileMenu();
325→		if (window.innerWidth < 768) {
326→			toggleSessions();
327→		}
328→	});
329→}
330→if (mobileMenuLogoutBtn) {
331→	mobileMenuLogoutBtn.addEventListener("click", performLogout);
332→}
333→window.addEventListener("resize", () => {
334→	if (window.innerWidth >= 768) closeMobileMenu();
335→});
336→document.addEventListener("keydown", (e) => {
337→	if (e.key === "Escape") closeMobileMenu();
338→});
339→document.addEventListener("click", (e) => {
340→	if (!mobileMenuPanel?.classList.contains("open")) return;
341→	if (mobileMenuPanel.contains(e.target as Node)) return;
342→	if (mobileMenuBtn?.contains(e.target as Node)) return;
343→	closeMobileMenu();
344→});
