601→function initSessionTabBar(): void {
602→	const bar = S.$("sessionTabBar");
603→	if (!bar) return;
604→	const buttons = bar.querySelectorAll<HTMLElement>(".session-tab");
605→	const archivedRow = S.$("archivedSessionsRow");
606→
607→	function updateActive(): void {
608→		const current = sessionStore.sessionListTab.value;
609→		for (const btn of buttons) {
610→			btn.classList.toggle("active", btn.dataset.tab === current);
611→		}
612→		if (archivedRow) {
613→			archivedRow.classList.toggle("hidden", current !== "sessions");
614→		}
615→	}
616→
617→	for (const btn of buttons) {
618→		btn.addEventListener("click", function (this: HTMLElement) {
619→			sessionStore.setSessionListTab(this.dataset.tab || "sessions");
620→			updateActive();
621→		});
622→	}
623→	updateActive();
624→}
